import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.BD9pLfSD.js";const g=JSON.parse('{"title":"MCP Integration: The Universal Interface","description":"","frontmatter":{},"headers":[],"relativePath":"docs/architecture/mcp-integration.md","filePath":"docs/architecture/mcp-integration.md"}'),i={name:"docs/architecture/mcp-integration.md"};function n(l,e,s,c,d,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="mcp-integration-the-universal-interface" tabindex="-1">MCP Integration: The Universal Interface <a class="header-anchor" href="#mcp-integration-the-universal-interface" aria-label="Permalink to &quot;MCP Integration: The Universal Interface&quot;">​</a></h1><p>xB77 is built on the <strong>Model Context Protocol (MCP)</strong>, an open standard that enables AI models to interact with external tools and data sources seamlessly.</p><h2 id="why-mcp" tabindex="-1">Why MCP? <a class="header-anchor" href="#why-mcp" aria-label="Permalink to &quot;Why MCP?&quot;">​</a></h2><ul><li><strong>Model Agnostic:</strong> Whether you use Claude, GPT-4, or a local Llama model, the interface remains the same.</li><li><strong>Strict Security:</strong> Tools are explicitly defined. The LLM cannot execute arbitrary code; it can only request execution of validated financial tools.</li><li><strong>Context Awareness:</strong> The agent provides real-time state snapshots (balance, treasury efficiency, latest receipts) directly into the LLM&#39;s context window.</li></ul><h2 id="available-tools" tabindex="-1">Available Tools <a class="header-anchor" href="#available-tools" aria-label="Permalink to &quot;Available Tools&quot;">​</a></h2><p>The xB77 MCP Server exposes the following core capabilities:</p><ul><li><code>agent.pay</code>: Executes a payment with autonomous strategy selection.</li><li><code>agent.strategy.evaluate</code>: Pre-screens a transaction for risk and compliance.</li><li><code>agent.status</code>: Retrieves the current financial health of the agent.</li><li><code>agent.audit.report</code>: Generates a ZK-certified selective disclosure for a specific receipt.</li><li><code>cfo.treasury.rebalance</code>: Triggers autonomous liquidity management between rails.</li></ul><hr><h1 id="integracion-mcp-la-interfaz-universal-es" tabindex="-1">Integración MCP: La Interfaz Universal (ES) <a class="header-anchor" href="#integracion-mcp-la-interfaz-universal-es" aria-label="Permalink to &quot;Integración MCP: La Interfaz Universal (ES)&quot;">​</a></h1><p>xB77 está construido sobre el <strong>Model Context Protocol (MCP)</strong>, un estándar abierto que permite a los modelos de IA interactuar con herramientas externas.</p><h2 id="¿por-que-mcp" tabindex="-1">¿Por qué MCP? <a class="header-anchor" href="#¿por-que-mcp" aria-label="Permalink to &quot;¿Por qué MCP?&quot;">​</a></h2><ul><li><strong>Agnóstico al Modelo:</strong> Funciona con cualquier IA (Claude, GPT, etc.).</li><li><strong>Seguridad Estricta:</strong> La IA solo puede ejecutar herramientas financieras validadas, no código arbitrario.</li><li><strong>Contexto en Tiempo Real:</strong> El agente inyecta estados financieros directamente en la &quot;ventana de contexto&quot; de la IA.</li></ul><h2 id="herramientas-disponibles" tabindex="-1">Herramientas Disponibles <a class="header-anchor" href="#herramientas-disponibles" aria-label="Permalink to &quot;Herramientas Disponibles&quot;">​</a></h2><ul><li><code>agent.pay</code>: Ejecuta un pago con selección de estrategia autónoma.</li><li><code>agent.strategy.evaluate</code>: Escanea riesgos antes de pagar.</li><li><code>agent.audit.report</code>: Genera un recibo certificado con ZK.</li></ul>',14)])])}const p=a(i,[["render",n]]);export{g as __pageData,p as default};
